package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.Reader;
import java.io.Serializable;
import java.sql.ResultSet;
import java.sql.ResultSetMetaData;
import java.sql.SQLException;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Field;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.apache.commons.csv.QuoteMode;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormatDefault;

    @BeforeEach
    public void setUp() {
        csvFormatDefault = CSVFormat.DEFAULT;
    }

    @Test
    public void testFormat_withNormalValues() throws Exception {
        String result = csvFormatDefault.format("a", "b", "c");
        // The default delimiter is COMMA, quote char is DOUBLE_QUOTE_CHAR, record separator CRLF
        assertEquals("\"a\",\"b\",\"c\"", result);
    }

    @Test
    public void testFormat_withNullValue() throws Exception {
        CSVFormat format = csvFormatDefault.withNullString("NULL");
        String result = format.format("a", null, "c");
        assertEquals("\"a\",NULL,\"c\"", result);
    }

    @Test
    public void testFormat_withEmptyValues() throws Exception {
        String result = csvFormatDefault.format();
        assertEquals("", result);
    }

    @Test
    public void testFormat_withValuesContainingDelimiterAndQuote() throws Exception {
        String val1 = "value,with,commas";
        String val2 = "value \"with\" quotes";
        String result = csvFormatDefault.format(val1, val2);
        // Values should be quoted and quotes escaped
        assertEquals("\"value,with,commas\",\"value \"\"with\"\" quotes\"", result);
    }

    @Test
    public void testFormat_throwsIllegalStateExceptionOnIOException() throws Exception {
        // Create a subclass of CSVFormat that overrides format to inject mocked CSVPrinter throwing IOException
        CSVFormat format = new CSVFormatWrapper(csvFormatDefault);

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> {
            format.format("a");
        });
        assertTrue(thrown.getCause() instanceof IOException);
        assertEquals("mock IO exception", thrown.getCause().getMessage());
    }

    private static class CSVFormatWrapper extends CSVFormat {

        private final CSVFormat delegate;

        CSVFormatWrapper(CSVFormat delegate) throws Exception {
            // Use reflection to invoke the private constructor of CSVFormat with the same parameters as delegate
            super(getCharField(delegate, "delimiter"),
                    getCharacterField(delegate, "quoteCharacter"),
                    getQuoteModeField(delegate, "quoteMode"),
                    getCharacterField(delegate, "commentMarker"),
                    getCharacterField(delegate, "escapeCharacter"),
                    getBooleanField(delegate, "ignoreSurroundingSpaces"),
                    getBooleanField(delegate, "ignoreEmptyLines"),
                    getStringField(delegate, "recordSeparator"),
                    getStringField(delegate, "nullString"),
                    getObjectArrayField(delegate, "headerComments"),
                    getStringArrayField(delegate, "header"),
                    getBooleanField(delegate, "skipHeaderRecord"),
                    getBooleanField(delegate, "allowMissingColumnNames"),
                    getBooleanField(delegate, "ignoreHeaderCase"));
            this.delegate = delegate;
        }

        @Override
        public String format(final Object... values) {
            try {
                StringWriter out = new StringWriter();
                CSVPrinter printer = mock(CSVPrinter.class);
                // Disambiguate printRecord by casting to varargs method using Object[]
                doThrow(new IOException("mock IO exception")).when(printer).printRecord((Object[]) any());
                printer.printRecord(values);
                return "";
            } catch (final IOException e) {
                throw new IllegalStateException(e);
            }
        }

        private static char getCharField(CSVFormat obj, String fieldName) throws Exception {
            Field f = CSVFormat.class.getDeclaredField(fieldName);
            f.setAccessible(true);
            return f.getChar(obj);
        }

        private static Character getCharacterField(CSVFormat obj, String fieldName) throws Exception {
            Field f = CSVFormat.class.getDeclaredField(fieldName);
            f.setAccessible(true);
            return (Character) f.get(obj);
        }

        private static QuoteMode getQuoteModeField(CSVFormat obj, String fieldName) throws Exception {
            Field f = CSVFormat.class.getDeclaredField(fieldName);
            f.setAccessible(true);
            return (QuoteMode) f.get(obj);
        }

        private static boolean getBooleanField(CSVFormat obj, String fieldName) throws Exception {
            Field f = CSVFormat.class.getDeclaredField(fieldName);
            f.setAccessible(true);
            return f.getBoolean(obj);
        }

        private static String getStringField(CSVFormat obj, String fieldName) throws Exception {
            Field f = CSVFormat.class.getDeclaredField(fieldName);
            f.setAccessible(true);
            return (String) f.get(obj);
        }

        private static Object[] getObjectArrayField(CSVFormat obj, String fieldName) throws Exception {
            Field f = CSVFormat.class.getDeclaredField(fieldName);
            f.setAccessible(true);
            return (Object[]) f.get(obj);
        }

        private static String[] getStringArrayField(CSVFormat obj, String fieldName) throws Exception {
            Field f = CSVFormat.class.getDeclaredField(fieldName);
            f.setAccessible(true);
            return (String[]) f.get(obj);
        }
    }

    @Test
    public void testFormat_withSingleNullValue() throws Exception {
        CSVFormat format = csvFormatDefault.withNullString("NULL");
        String result = format.format((Object) null);
        assertEquals("NULL", result);
    }

    @Test
    public void testFormat_withMixedNullAndEmptyString() throws Exception {
        CSVFormat format = csvFormatDefault.withNullString("NULL");
        String result = format.format(null, "", "value");
        assertEquals("NULL,\"\",\"value\"", result);
    }

    @Test
    public void testFormat_withCustomQuoteCharacter() throws Exception {
        CSVFormat format = csvFormatDefault.withQuote('\'');
        String result = format.format("val1", "val,2");
        assertEquals("'val1','val,2'", result);
    }

    @Test
    public void testFormat_withNoQuoteCharacter() throws Exception {
        CSVFormat format = csvFormatDefault.withQuote((Character) null);
        String result = format.format("val1", "val,2");
        // Without quote character, delimiter in value should not be quoted, so it may break CSV but test as is
        assertEquals("val1,val,2", result);
    }
}
